import React from 'react';
import { useCurrentFrame, useVideoConfig, interpolate, spring } from 'remotion';
import { z } from 'zod';
import { DURATION, SPRING_SMOOTH } from '../../../lib/motion';

/** Zod schema for {@link MaskReveal} props. */
export const maskRevealSchema = z.object({
  /** What to reveal. */
  text: z.string().default('Onda'),
  /** Frames before the animation starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames for the mask to fully retreat. */
  duration: z.number().int().min(1).default(DURATION.base),
  /** The side the text appears to come *in* from (mirrors `SlideIn`). */
  direction: z.enum(['left', 'right', 'top', 'bottom']).default('left'),
  /** Text color. Defaults to `--onda-text` (`#F2F2F4`). */
  color: z.string().default('#F2F2F4'),
  /** Pixels. */
  fontSize: z.number().default(96),
  /** Onda display font. */
  fontFamily: z.string().default('"Clash Display", sans-serif'),
});

/** Inferred props for {@link MaskReveal}. */
export type MaskRevealProps = z.infer<typeof maskRevealSchema>;

/**
 * Reveals text from behind a retreating clip-path mask. Hard, pixel-sharp
 * edge by design — no opacity fade. The moving edge IS the fingerprint.
 *
 * @example
 * <MaskReveal text="Onda" direction="left" />
 */
export const MaskReveal: React.FC<MaskRevealProps> = ({
  text, delay, duration, direction, color, fontSize, fontFamily,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const local = Math.max(0, frame - delay);

  // Spring-driven mask retreat. The text is rendered fully from frame 0;
  // only the clip-path inset shrinks, so the reveal edge stays crisp —
  // that hard edge IS the fingerprint of this primitive. No opacity fade.
  const progress = spring({
    frame: local,
    fps,
    config: SPRING_SMOOTH,
    durationInFrames: duration,
  });

  // Percentage of the element still covered by the mask: 100 → 0.
  const cover = interpolate(progress, [0, 1], [100, 0], {
    extrapolateLeft: 'clamp', extrapolateRight: 'clamp',
  });

  // `direction` names the side the text comes IN from (mirrors SlideIn).
  // So the mask sits on the OPPOSITE side and retreats toward that side.
  //   inset(top right bottom left)
  let clipPath: string;
  switch (direction) {
    case 'left':
      // text enters from the left → mask covers the right side
      clipPath = `inset(0 ${cover}% 0 0)`;
      break;
    case 'right':
      // text enters from the right → mask covers the left side
      clipPath = `inset(0 0 0 ${cover}%)`;
      break;
    case 'top':
      // text enters from the top → mask covers the bottom
      clipPath = `inset(0 0 ${cover}% 0)`;
      break;
    case 'bottom':
      // text enters from the bottom → mask covers the top
      clipPath = `inset(${cover}% 0 0 0)`;
      break;
  }

  return (
    <div style={{
      clipPath,
      WebkitClipPath: clipPath,
      color, fontSize, fontFamily, fontWeight: 600,
    }}>
      {text}
    </div>
  );
};

// Re-exports the Zod schema so tooling (registry builds, docs site,
// training-data pipelines) can consume props validation without pulling
// in the component itself.
export { maskRevealSchema, type MaskRevealProps } from './MaskReveal';

# MaskReveal

Reveals text from behind a retreating mask. The text renders fully from frame 0; a spring-driven `clip-path` inset shrinks from 100% to 0%, uncovering the text edge-by-edge with a crisp hard line. No opacity fade — the hard mask edge is the fingerprint of this primitive.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `text` | `string` | `"Onda"` | What to reveal. |
| `delay` | `integer ≥ 0` | `0` | Frames before the animation starts. |
| `duration` | `integer ≥ 1` | `DURATION.base` (18) | Target frames to fully uncover. With `SPRING_SMOOTH` the visible motion settles in roughly this range. |
| `direction` | `'left' \| 'right' \| 'top' \| 'bottom'` | `'left'` | The side the text comes IN from. Mirrors `SlideIn`'s convention — the mask sits on the OPPOSITE side and retreats toward this one. |
| `color` | `string` | `"#F2F2F4"` | Text color — defaults to `--onda-text`. |
| `fontSize` | `number` | `96` | Pixels. |
| `fontFamily` | `string` | `'"Clash Display", sans-serif'` | The Onda display font. Never default to Inter / Arial / system. |

## Usage

```tsx
import { Composition } from 'remotion';
import { MaskReveal, maskRevealSchema } from './components/onda/mask-reveal/MaskReveal';

export const Root: React.FC = () => (
  <Composition
    id="MyMaskReveal"
    component={MaskReveal}
    durationInFrames={60}
    fps={30}
    width={1080}
    height={1920}
    schema={maskRevealSchema}
    defaultProps={{
      text: 'Hello',
      delay: 0,
      duration: 18,
      direction: 'left',
      color: '#F2F2F4',
      fontSize: 96,
      fontFamily: '"Clash Display", sans-serif',
    }}
  />
);
```

## Motion notes

- **Direction names the side the text comes IN from** — same convention as `SlideIn`. With `direction: 'left'` the text appears from the left edge first, so the mask covers the **right** side and retreats rightward (`inset(0 cover% 0 0)`). `'right'` mirrors it (`inset(0 0 0 cover%)`); `'top'` and `'bottom'` do the vertical equivalents.
- **Opacity is intentionally unanimated.** The brand of this primitive is the hard reveal edge — fading would blur that signature. The text is rendered at full opacity from frame 0; only the clip path moves.
- Spring is `SPRING_SMOOTH` from `lib/motion.ts` — the Onda house default. No overshoot; the mask edge slides to rest, it doesn't snap or bounce past.
- Duration defaults to `DURATION.base` (18 frames ≈ 0.6s at 30fps).
- Both `clipPath` and `WebkitClipPath` are set for cross-browser support — Safari (including current iOS WebKit and Chromium renderers used by Remotion/Headless Chrome) honors the unprefixed form, but the `-webkit-` alias is kept as a safety net for any older WebKit-based environment in the toolchain.
- All `interpolate` calls clamp at both ends — the component is correct on frame 0 (fully masked) and on any frame past `delay + duration` (fully revealed).
